// ============================================================
// PDF.CO FIRST PAGE GENERATION
// ============================================================

async function generateFirstPagePdf(html: string): Promise<string> {
  console.log('[FIRST PAGE] Generating PDF with PDF.co...')

  const response = await fetch('https://api.pdf.co/v1/pdf/convert/from/html', {
    method: 'POST',
    headers: {
      'x-api-key': PDFCO_API_KEY,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({
      html: html,
      name: `smart_report_cover_${Date.now()}.pdf`,
      paperSize: 'A4',
      margins: '0px 0px 0px 0px',
      async: false,
      printBackground: true,
    }),
  })

  if (!response.ok) {
    const errorText = await response.text()
    throw new Error(`PDF.co first page generation failed: ${errorText}`)
  }

  const result = await response.json()

  if (result.error) {
    throw new Error(`PDF.co error: ${result.message}`)
  }

  console.log('[FIRST PAGE] PDF generated:', result.url)
  return result.url
}

