async function generateGammaContent(inputText: string): Promise<string> {
  console.log('[GAMMA] Starting generation...')
  console.log('[GAMMA] Input length:', inputText.length)

  // 1. Initiate Generation
  const initiateResponse = await fetch('https://public-api.gamma.app/v1.0/generations', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'X-API-KEY': GAMMA_API_KEY,
      'accept': 'application/json'
    },
    body: JSON.stringify({
      textMode: 'generate',
      inputText: inputText,
      format: 'document',
      themeId: 'wbpgwj9c0ty5wbo', // Clean medical theme
      cardSplit: 'inputTextBreaks',
      additionalInstructions: GAMMA_INSTRUCTIONS,
      exportAs: 'pdf',
      sharingOptions: {
        workspaceAccess: 'edit',
        externalAccess: 'view'
      },
      imageOptions: {
        source: 'noImages' // No stock images
      }
    })
  })

  if (!initiateResponse.ok) {
    const errText = await initiateResponse.text()
    throw new Error(`Gamma API init failed: ${initiateResponse.status} - ${errText}`)
  }

  const initData = await initiateResponse.json()
  const generationId = initData.generationId

  if (!generationId) {
    throw new Error('No generation ID received from Gamma')
  }

  console.log('[GAMMA] Generation started:', generationId)

  // 2. Poll for Completion
  let attempts = 0
  const maxAttempts = 60 // ~2 minutes
  let result = null

  while (attempts < maxAttempts) {
    attempts++
    await new Promise(resolve => setTimeout(resolve, 2000))

    const pollResponse = await fetch(`https://public-api.gamma.app/v1.0/generations/${generationId}`, {
      method: 'GET',
      headers: {
        'X-API-KEY': GAMMA_API_KEY,
        'accept': 'application/json'
      }
    })

    if (!pollResponse.ok) {
      console.warn(`[GAMMA] Poll attempt ${attempts} failed`)
      continue
    }

    const pollData = await pollResponse.json()
    console.log(`[GAMMA] Poll status (${attempts}):`, pollData.status)

    if (pollData.status === 'completed') {
      result = pollData
      break
    } else if (pollData.status === 'error' || pollData.status === 'failed') {
      throw new Error(`Gamma generation failed: ${JSON.stringify(pollData)}`)
    }
  }

  if (!result) {
    throw new Error('Gamma generation timed out')
  }

  const exportUrl = result.exportUrl || result.pdfUrl
  if (!exportUrl) {
    throw new Error('No PDF URL in Gamma response')
  }

  console.log('[GAMMA] PDF ready:', exportUrl)
  return exportUrl
}

// ============================================================
// PDF MERGE WITH PDF.CO
// ============================================================

async function mergePdfs(firstPageUrl: string, gammaUrl: string, orderId: string): Promise<string> {
  console.log('[MERGE] Merging PDFs...')
  console.log('[MERGE] First page:', firstPageUrl)
  console.log('[MERGE] Gamma pages:', gammaUrl)

  const response = await fetch('https://api.pdf.co/v1/pdf/merge', {
    method: 'POST',
    headers: {
      'x-api-key': PDFCO_API_KEY,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      url: `${firstPageUrl},${gammaUrl}`,
      name: `SmartReport_${orderId}_${Date.now()}.pdf`,
      async: false
    })
  })

  if (!response.ok) {
    const errorText = await response.text()
    throw new Error(`PDF merge failed: ${errorText}`)
  }

  const result = await response.json()

  if (result.error) {
    throw new Error(`PDF.co merge error: ${result.message}`)
  }

  console.log('[MERGE] Merged PDF:', result.url)
  return result.url
}

// ============================================================
// STORAGE & DATABASE
// ============================================================

async function uploadToStorage(
  supabase: any,
  pdfUrl: string,
  orderId: string,
  labId: string
): Promise<string> {
  console.log('[STORAGE] Downloading merged PDF...')

  const pdfResponse = await fetch(pdfUrl)
  if (!pdfResponse.ok) {
    throw new Error('Failed to download merged PDF')
  }

  const pdfBuffer = await pdfResponse.arrayBuffer()

  const timestamp = Date.now()
  const storagePath = `smart-reports/${labId}/${orderId}_${timestamp}.pdf`

  console.log('[STORAGE] Uploading to:', storagePath)

  const { error: uploadError } = await supabase.storage
    .from('reports')
    .upload(storagePath, pdfBuffer, {
      contentType: 'application/pdf',
      cacheControl: '3600',
      upsert: true
    })

  if (uploadError) {
    throw new Error(`Upload failed: ${uploadError.message}`)
  }

  // Get public URL (using custom domain if configured, same as generate-pdf-letterhead)
  const publicUrl = getPublicStorageUrl('reports', storagePath)

  console.log('[STORAGE] Public URL:', publicUrl)
  console.log('[STORAGE] Using custom domain:', !!CUSTOM_REPORTS_DOMAIN)
  return publicUrl
}

async function updateDatabase(supabase: any, orderId: string, pdfUrl: string): Promise<void> {
  console.log('[DB] Updating orders table...')

  const { error } = await supabase
    .from('orders')
    .update({
      smart_report_url: pdfUrl,
      smart_report_generated_at: new Date().toISOString()
    })
    .eq('id', orderId)

  if (error) {
    console.error('[DB] Update failed:', error)
    // Non-fatal - PDF is still accessible
  } else {
    console.log('[DB] Updated successfully')
  }
}

// ============================================================
// MAIN HANDLER
// ============================================================

serve(async (req) => {
  if (req.method === 'OPTIONS') {
    return new Response('ok', { headers: corsHeaders })
  }

  try {
    const { orderId, forceRegenerate } = await req.json()

    if (!orderId) {
      throw new Error('Missing required parameter: orderId')
    }

    console.log('========================================')
    console.log('[SMART REPORT V2] Starting for order:', orderId)
    console.log('[SMART REPORT V2] Force regenerate:', forceRegenerate || false)
    console.log('========================================')

    const supabaseUrl = Deno.env.get('SUPABASE_URL') ?? ''
    const supabaseKey = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY') ?? ''
    const supabase = createClient(supabaseUrl, supabaseKey)

    // ============================================================
    // CACHING CHECK: Return existing report if available
    // ============================================================
    if (!forceRegenerate) {
      console.log('[CACHE] Checking for existing smart report...')

      const { data: existingOrder, error: orderCheckError } = await supabase
        .from('orders')
        .select('smart_report_url, smart_report_generated_at')
        .eq('id', orderId)
        .single()

      if (!orderCheckError && existingOrder?.smart_report_url) {
        console.log('[CACHE] Found existing report:', existingOrder.smart_report_url)
        console.log('[CACHE] Generated at:', existingOrder.smart_report_generated_at)

        // Verify the URL is accessible (quick HEAD check)
        try {
          const headResponse = await fetch(existingOrder.smart_report_url, {
            method: 'HEAD',
            headers: { 'Accept': 'application/pdf' }
          })

          if (headResponse.ok) {
            console.log('[CACHE] Report URL is valid and accessible')
            return new Response(
              JSON.stringify({
                success: true,
                pdfUrl: existingOrder.smart_report_url,
                cached: true,
                generatedAt: existingOrder.smart_report_generated_at,
                message: 'Returning cached smart report. Use forceRegenerate: true to generate a new one.'
              }),
              {
                headers: { ...corsHeaders, 'Content-Type': 'application/json' },
                status: 200
              }
            )
          } else {
            console.log('[CACHE] Report URL returned', headResponse.status, '- will regenerate')
          }
        } catch (fetchError) {
          console.log('[CACHE] Could not verify URL accessibility:', fetchError)
          // Proceed with regeneration
        }
      } else {
        console.log('[CACHE] No existing smart report found')
      }
    } else {
      console.log('[CACHE] Force regenerate requested - skipping cache check')
    }

    // 1. Fetch Report Context
    console.log('[STEP 1] Fetching report context...')
    const { data: context, error: contextError } = await supabase.rpc(
      'get_report_template_context',
      { p_order_id: orderId }
    )

    if (contextError || !context) {
      throw new Error(`Context fetch failed: ${contextError?.message}`)
    }

    // Get lab_id from order
    const { data: orderData } = await supabase
      .from('orders')
      .select('lab_id')
      .eq('id', orderId)
      .single()

    const labId = orderData?.lab_id || context.order?.lab_id

    // 2. Fetch Letterhead
    console.log('[STEP 2] Fetching letterhead...')
    const letterheadUrl = await fetchLetterheadBackgroundForOrder(supabase, orderId, labId)
    console.log('[STEP 2] Letterhead URL:', letterheadUrl || 'None')

    // 3. Get Lab Info
    const { data: labInfo } = await supabase
      .from('labs')
      .select('name, address, phone, email')
      .eq('id', labId)
      .single()

    // 3b. Fetch Signatory from lab_user_signatures
    console.log('[STEP 3b] Fetching signatory...')
    let signatoryName = ''
    let signatoryImageUrl = ''

    // First try to get from lab_user_signatures (default signature for the lab)
    const { data: labSignature } = await supabase
      .from('lab_user_signatures')
      .select('signature_name, imagekit_url, file_url, variants')
      .eq('lab_id', labId)
      .eq('is_active', true)
      .eq('is_default', true)
      .order('created_at', { ascending: false })
      .limit(1)
      .maybeSingle()

    if (labSignature) {
      signatoryName = labSignature.signature_name || ''
      // Prefer optimized variant, then imagekit_url, then file_url
      if (labSignature.variants) {
        const variants = typeof labSignature.variants === 'string'
          ? JSON.parse(labSignature.variants)
          : labSignature.variants
        signatoryImageUrl = variants?.optimized || variants?.webp || ''
      }
      if (!signatoryImageUrl) {
        signatoryImageUrl = labSignature.imagekit_url || labSignature.file_url || ''
      }
      console.log('[STEP 3b] Found signatory:', signatoryName, signatoryImageUrl ? '(with image)' : '(no image)')
    } else {
      console.log('[STEP 3b] No default lab signature found')
    }

    // 4. Extract test group info
    const testGroupIds = context.testGroupIds || []
    let testGroups: { id: string; name: string }[] = []

    if (testGroupIds.length > 0) {
      const { data: tgData } = await supabase
        .from('test_groups')
        .select('id, name')
        .in('id', testGroupIds)

      testGroups = tgData || []
    }

    // Fallback if no test groups
    if (testGroups.length === 0) {
      testGroups = [{ id: 'default', name: 'Laboratory Tests' }]
    }

    // 5. Build First Page Context
    const placeholders = context.placeholderValues || {}
    const firstPageCtx: FirstPageContext = {
      labName: labInfo?.name || placeholders.labName || 'Laboratory',
      labAddress: labInfo?.address || '',
      labPhone: labInfo?.phone || '',
      labEmail: labInfo?.email || '',
      patientName: context.patient?.name || placeholders.patientName || '',
      patientAge: context.patient?.age?.toString() || placeholders.patientAge || '',
      patientGender: context.patient?.gender || placeholders.patientGender || '',
      patientPhone: context.patient?.mobile || context.patient?.phone || '',
      sampleId: context.order?.sampleId || placeholders.sampleId || '',
      orderDate: placeholders.reportDate || new Date().toLocaleDateString('en-IN'),
      collectionDate: placeholders.collectionTime || '',
      doctorName: placeholders.referringDoctor || context.order?.referringDoctorName || '',
      testGroups: testGroups,
      signatoryName: signatoryName,
      signatoryImageUrl: signatoryImageUrl
    }

    // 6. Build Gamma Input Data
    const analytes = context.analytes || []
    const analytesByGroup = new Map<string, AnalyteData[]>()

    // Group analytes by test_group_id
    for (const analyte of analytes) {
      const groupId = analyte.test_group_id || 'ungrouped'
      if (!analytesByGroup.has(groupId)) {
        analytesByGroup.set(groupId, [])
      }
      analytesByGroup.get(groupId)?.push({
        parameter: analyte.parameter || analyte.name || 'Unknown',
        value: analyte.value,
        unit: analyte.unit || '',
        referenceRange: analyte.referenceRange || analyte.reference_range || '',
        flag: analyte.flag || 'Normal',
        interpretation: analyte.interpretation
      })
    }

    // Build test groups data for Gamma
    const testGroupsData: TestGroupData[] = []
    for (const group of testGroups) {
      const groupAnalytes = analytesByGroup.get(group.id) || analytesByGroup.get('ungrouped') || []
      if (groupAnalytes.length > 0) {
        testGroupsData.push({
          id: group.id,
          name: group.name,
          analytes: groupAnalytes
        })
      }
    }

    // If still empty, create a fallback with all analytes
    if (testGroupsData.length === 0 && analytes.length > 0) {
      testGroupsData.push({
        id: 'all',
        name: 'Test Results',
        analytes: analytes.map((a: any) => ({
          parameter: a.parameter || a.name || 'Unknown',
          value: a.value,
          unit: a.unit || '',
          referenceRange: a.referenceRange || a.reference_range || '',
          flag: a.flag || 'Normal'
        }))
      })
    }

    // 7. Get AI Patient Summary for rich content
    console.log('[STEP 7] Getting AI patient summary for rich insights...')

    // Prepare data for AI analysis
    const aiTestGroups = testGroupsData.map(tg => ({
      name: tg.name,
      category: 'Laboratory',
      result_values: tg.analytes.map(a => ({
        analyte_name: a.parameter,
        value: String(a.value),
        unit: a.unit,
        reference_range: a.referenceRange,
        flag: a.flag === 'Normal' ? 'N' : a.flag === 'High' ? 'H' : a.flag === 'Low' ? 'L' : a.flag
      }))
    }))

    const aiSummary = await getAIPatientSummary(
      aiTestGroups,
      {
        age: parseInt(firstPageCtx.patientAge) || undefined,
        gender: firstPageCtx.patientGender || undefined
      }
    )

    // 8. Generate First Page & Gamma Content in Parallel
    console.log('[STEP 8] Generating PDFs in parallel...')

    const firstPageHtml = buildFirstPageHtml(firstPageCtx, letterheadUrl)

    // Use enhanced input if AI summary available, otherwise fallback
    const gammaInput = aiSummary
      ? buildEnhancedGammaInput(testGroupsData, firstPageCtx.patientAge, firstPageCtx.patientGender, aiSummary)
      : buildBasicGammaInput(testGroupsData, firstPageCtx.patientAge, firstPageCtx.patientGender)

    console.log('[STEP 8] Gamma input length:', gammaInput.length, aiSummary ? '(AI-enhanced)' : '(basic)')

    const [firstPageUrl, gammaUrl] = await Promise.all([
      generateFirstPagePdf(firstPageHtml),
      generateGammaContent(gammaInput)
    ])

    // 9. Merge PDFs
    console.log('[STEP 9] Merging PDFs...')
    const mergedUrl = await mergePdfs(firstPageUrl, gammaUrl, orderId)

    // 10. Upload to Storage
    console.log('[STEP 10] Uploading to storage...')
    const publicUrl = await uploadToStorage(supabase, mergedUrl, orderId, labId)

    // 11. Update Database
    console.log('[STEP 11] Updating database...')
    await updateDatabase(supabase, orderId, publicUrl)

    console.log('========================================')
    console.log('[SMART REPORT V2] Complete!')
    console.log('========================================')

    return new Response(
      JSON.stringify({
        success: true,
        pdfUrl: publicUrl,
        mergedUrl: mergedUrl,
        gammaUrl: gammaUrl,
        firstPageUrl: firstPageUrl
      }),
      {
        headers: { ...corsHeaders, 'Content-Type': 'application/json' },
        status: 200
      }
    )

  } catch (error) {
    console.error('[SMART REPORT V2] Error:', error)
    return new Response(
      JSON.stringify({
        success: false,
        error: error instanceof Error ? error.message : 'Unknown error'
      }),
      {
        headers: { ...corsHeaders, 'Content-Type': 'application/json' },
        status: 400
      }
    )
  }
})
